/**
 * L0 Gateway Creation — Implementation
 *
 * Creates the AI Gateway via REST API if it doesn't already exist.
 *
 * PREREQUISITE: CF_API_TOKEN env var must be set with a CF dashboard API token
 * that has "Cloudflare AI Gateway: Edit" permission.
 * The wrangler OAuth token (IAL-... format) is rejected by this API with HTTP 403.
 */

import { loadToken, listGateways, getGateway, createGateway, type GatewayConfig } from './gateway-api.js';

export const GATEWAY_CONFIG: GatewayConfig = {
  id: 'agent-univ-test-gateway-01',
  cache_invalidate_on_update: false,
  cache_ttl: 0,
  collect_logs: true,
  rate_limiting_interval: 0,
  rate_limiting_limit: 0,
  rate_limiting_technique: 'fixed',
};

export interface CreateResult {
  action: 'created' | 'already-exists' | 'error';
  status: number;
  gatewayId: string;
  error?: string;
}

/**
 * Idempotently create the gateway.
 * If it already exists, return 'already-exists' instead of failing.
 */
export async function ensureGatewayExists(token: string): Promise<CreateResult> {
  // Check if it already exists
  const existing = await getGateway(token, GATEWAY_CONFIG.id);
  if (existing.status === 200 && existing.body.success) {
    return { action: 'already-exists', status: 200, gatewayId: GATEWAY_CONFIG.id };
  }

  // Create it
  const result = await createGateway(token, GATEWAY_CONFIG);
  if (result.status === 200 || result.status === 201) {
    return { action: 'created', status: result.status, gatewayId: GATEWAY_CONFIG.id };
  }

  return {
    action: 'error',
    status: result.status,
    gatewayId: GATEWAY_CONFIG.id,
    error: result.body.errors?.[0]?.message ?? `HTTP ${result.status}`,
  };
}

// If run directly as a script
if (import.meta.url === `file://${process.argv[1]}`) {
  const tokenResult = loadToken();
  if (!tokenResult) {
    console.error('ERROR: No token found. Set CF_API_TOKEN env var.');
    process.exit(1);
  }
  console.log(`Token source: ${tokenResult.source}`);
  const result = await ensureGatewayExists(tokenResult.token);
  console.log(`Gateway action: ${result.action}`);
  if (result.error) console.error(`Error: ${result.error}`);
  process.exit(result.action === 'error' ? 1 : 0);
}

