/**
 * Cloudflare AI Gateway — REST API client
 *
 * Token sourcing priority:
 * 1. CF_API_TOKEN env variable (proper API token from dashboard)
 * 2. CLOUDFLARE_API_TOKEN env variable (alternative name)
 * 3. oauth_token from ~/.wrangler/config/default.toml (OAuth token — may be rejected by ai-gateway API)
 *
 * KNOWN BLOCKER (2026-05-17): The wrangler OAuth token (IAL-... format) is rejected
 * with HTTP 403 / error code 10000 by the /ai-gateway/gateways management endpoints,
 * even though it works for /ai/models/search. A proper API Token created in the CF
 * dashboard with AI Gateway permissions is required.
 */

import { readFileSync } from 'fs';
import { homedir } from 'os';
import { join } from 'path';

const ACCOUNT_ID = '6b9fef813cb442d218fd590d6f22fabe';
const CF_API_BASE = 'https://api.cloudflare.com/client/v4';

export interface GatewayConfig {
  id: string;
  cache_invalidate_on_update: boolean;
  cache_ttl: number;
  collect_logs: boolean;
  rate_limiting_interval: number;
  rate_limiting_limit: number;
  rate_limiting_technique: string;
}

export interface CFApiResponse<T> {
  success: boolean;
  result: T | null;
  errors: Array<{ code: number; message: string }>;
  messages: string[];
}

export interface TokenResult {
  token: string;
  source: 'env-CF_API_TOKEN' | 'env-CLOUDFLARE_API_TOKEN' | 'wrangler-oauth';
}

/**
 * Load authentication token without ever printing it.
 * Returns null if no token found.
 */
export function loadToken(): TokenResult | null {
  if (process.env.CF_API_TOKEN) {
    return { token: process.env.CF_API_TOKEN, source: 'env-CF_API_TOKEN' };
  }
  if (process.env.CLOUDFLARE_API_TOKEN) {
    return { token: process.env.CLOUDFLARE_API_TOKEN, source: 'env-CLOUDFLARE_API_TOKEN' };
  }
  try {
    const tomlPath = join(homedir(), 'Library/Preferences/.wrangler/config/default.toml');
    const toml = readFileSync(tomlPath, 'utf8');
    const match = toml.match(/oauth_token\s*=\s*"([^"]+)"/);
    if (match?.[1]) {
      return { token: match[1], source: 'wrangler-oauth' };
    }
  } catch {
    // TOML not found or unreadable
  }
  return null;
}

/**
 * List all gateways for the account.
 * Returns { status, success, result, errors }
 */
export async function listGateways(token: string): Promise<{
  status: number;
  body: CFApiResponse<GatewayConfig[]>;
}> {
  const url = `${CF_API_BASE}/accounts/${ACCOUNT_ID}/ai-gateway/gateways`;
  const resp = await fetch(url, {
    method: 'GET',
    headers: {
      Authorization: `Bearer ${token}`,
      'Content-Type': 'application/json',
    },
  });
  const body = (await resp.json()) as CFApiResponse<GatewayConfig[]>;
  return { status: resp.status, body };
}

/**
 * Get a specific gateway by ID.
 */
export async function getGateway(token: string, gatewayId: string): Promise<{
  status: number;
  body: CFApiResponse<GatewayConfig>;
}> {
  const url = `${CF_API_BASE}/accounts/${ACCOUNT_ID}/ai-gateway/gateways/${gatewayId}`;
  const resp = await fetch(url, {
    method: 'GET',
    headers: {
      Authorization: `Bearer ${token}`,
      'Content-Type': 'application/json',
    },
  });
  const body = (await resp.json()) as CFApiResponse<GatewayConfig>;
  return { status: resp.status, body };
}

/**
 * Create a new gateway.
 */
export async function createGateway(token: string, config: GatewayConfig): Promise<{
  status: number;
  body: CFApiResponse<GatewayConfig>;
}> {
  const url = `${CF_API_BASE}/accounts/${ACCOUNT_ID}/ai-gateway/gateways`;
  const resp = await fetch(url, {
    method: 'POST',
    headers: {
      Authorization: `Bearer ${token}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(config),
  });
  const body = (await resp.json()) as CFApiResponse<GatewayConfig>;
  return { status: resp.status, body };
}

