```ts
// POC L5 — Composio client helper.
//
// Same shape as L1's client factory: env-driven, fresh instance per call. The
// invalid-API-key scenario in `failures.test.ts` deliberately overrides the
// `apiKey` option with a bogus literal — this factory is the one place where
// `apiKey` overrides are accepted.

import { Composio } from '@composio/core';

export interface ComposioClientOptions {
  /** Override the env-derived API key (used by L5 scenario 3 with a bogus key). */
  apiKey?: string;
  /** Override the default https://backend.composio.dev base URL. */
  baseURL?: string;
}

export function createComposioClient(options: ComposioClientOptions = {}): Composio {
  const apiKey = options.apiKey ?? process.env.COMPOSIO_API_KEY;
  if (!apiKey) {
    throw new Error(
      'COMPOSIO_API_KEY env var not set — L5 (and the rest of the POCs) cannot run',
    );
  }
  const baseURL = options.baseURL ?? process.env.COMPOSIO_BASE_URL;
  return new Composio({
    apiKey,
    ...(baseURL ? { baseURL } : {}),
    // Stay quiet in test output. Default is true.
    allowTracking: false,
  });
}

