```ts
// Test label: Live behavioral test (failure-shape capture)
// POC: L5 — Failure Modes
//
// Four scenarios. Each one issues a REAL call that we expect to fail and
// asserts on the captured error shape. The point of L5 is to record what
// Composio's failure surfaces actually look like — error class, code, HTTP
// status, message — so future agents can recognize them from the field.
//
// NO MOCKS. Every error in this file came back from the live
// backend.composio.dev surface or the SDK's own validation path.

import { test, expect } from 'vitest';
import { createComposioClient } from './client.js';

/** Single-line JSON trace so green runs leave evidence in stdout. */
function trace(event: Record<string, unknown>): void {
  // eslint-disable-next-line no-console
  console.log(JSON.stringify({ poc: 'L5', ...event }));
}

/**
 * Capture an arbitrary error into a flat, serialisable record. Includes every
 * field future agents are likely to read: name, message, code, status, body,
 * cause, errorId, possibleFixes.
 */
function captureError(err: unknown): Record<string, unknown> {
  const e = err as {
    name?: string;
    message?: string;
    code?: string;
    status?: number;
    statusCode?: number;
    errorId?: string;
    possibleFixes?: string[];
    response?: unknown;
    body?: unknown;
    cause?: unknown;
    stack?: string;
  };
  return {
    kind: 'error',
    name: e?.name ?? null,
    constructor: (err as { constructor?: { name?: string } })?.constructor?.name ?? null,
    message: e?.message ?? null,
    code: e?.code ?? null,
    status: e?.status ?? e?.statusCode ?? null,
    errorId: e?.errorId ?? null,
    possibleFixes: e?.possibleFixes ?? null,
    body: e?.body ?? null,
    response: e?.response ?? null,
    causeName: (e?.cause as { name?: string } | undefined)?.name ?? null,
    causeMessage: (e?.cause as { message?: string } | undefined)?.message ?? null,
    stackHead: e?.stack ? String(e.stack).split('\n').slice(0, 3).join(' | ') : null,
  };
}

// ---------------------------------------------------------------------------
// L2 evidence — DO NOT delete or revoke this connection. Capstone needs it.
// ---------------------------------------------------------------------------
const L2_USER_ID = 'aischool-l2-1779381348316';
const L2_CONNECTED_ACCOUNT_ID = 'ca_4yzaRszW1RrO'; // ACTIVE github connection

// ---------------------------------------------------------------------------
// Scenario 1 — unknown user has no GitHub connection
// ---------------------------------------------------------------------------
test('S1 live: unknown user has no github connection -> failure surfaced', async () => {
  const composio = createComposioClient();
  const userId = `aischool-l5-noconnect-${Date.now()}`;
  let captured: Record<string, unknown>;
  try {
    const result = await composio.tools.execute('GITHUB_GET_THE_AUTHENTICATED_USER', {
      userId,
      arguments: {},
      version: '00000000_00',
    });
    captured = { kind: 'result', ...result };
  } catch (err) {
    captured = captureError(err);
  }
  trace({ scenario: 'S1-no-connection', user_id: userId, captured });

  // Accept either: SDK threw a recognisable connection/auth error, OR the
  // execute call returned `successful: false` with a connection-shaped error.
  const isFailure =
    (captured.kind === 'error' &&
      /(connect|account|auth|no.*connect|not.*found)/i.test(
        String(captured.message ?? ''),
      )) ||
    (captured.kind === 'result' &&
      (captured as { successful?: boolean }).successful === false);
  expect(
    isFailure,
    `expected failure for new user, got: ${JSON.stringify(captured).slice(0, 600)}`,
  ).toBe(true);
}, 60_000);

// ---------------------------------------------------------------------------
// Scenario 2 — schema violation on tool input (three variants)
// ---------------------------------------------------------------------------
test('S2 live: schema violation surfaces concrete error', async () => {
  const composio = createComposioClient();
  const userId = L2_USER_ID;

  // Discover the tool's actual input schema so we can record what "required"
  // really means.
  const candidates = ['GITHUB_GET_A_USER', 'GITHUB_GET_USER', 'GITHUB_USERS_GET_BY_USERNAME'];
  const probed = await composio.tools.get(userId, { tools: candidates });
  const probedList = probed as unknown[];
  const slugInfo = probedList
    .map((t) => {
      const obj = t as {
        function?: { name?: string; parameters?: Record<string, unknown> };
        name?: string;
        parameters?: Record<string, unknown>;
      };
      const name = obj?.function?.name ?? obj?.name ?? '';
      const parameters = obj?.function?.parameters ?? obj?.parameters ?? null;
      return { name, parameters };
    })
    .filter((s) => s.name);
  trace({
    scenario: 'S2-discover',
    candidates,
    discovered: slugInfo.map((s) => s.name),
    first_schema_keys: slugInfo[0]?.parameters
      ? Object.keys(slugInfo[0].parameters as Record<string, unknown>)
      : null,
    required: (slugInfo[0]?.parameters as { required?: string[] } | undefined)?.required ?? null,
    properties: (slugInfo[0]?.parameters as { properties?: Record<string, unknown> } | undefined)
      ?.properties
      ? Object.keys(
          (slugInfo[0].parameters as { properties: Record<string, unknown> }).properties,
        )
      : null,
  });
  expect(slugInfo.length, 'no matching schema-test tool found').toBeGreaterThan(0);
  const targetSlug = slugInfo[0].name;

  // Variant 2a — missing required field
  let cap2a: Record<string, unknown>;
  try {
    const res = await composio.tools.execute(targetSlug, {
      userId,
      arguments: {},
      version: '00000000_00',
    });
    cap2a = { kind: 'result', ...res };
  } catch (err) {
    cap2a = captureError(err);
  }
  trace({ scenario: 'S2a-missing-required', target_slug: targetSlug, captured: cap2a });

  // Variant 2b — wrong type
  let cap2b: Record<string, unknown>;
  try {
    const res = await composio.tools.execute(targetSlug, {
      userId,
      arguments: { username: 12345 } as unknown as Record<string, unknown>,
      version: '00000000_00',
    });
    cap2b = { kind: 'result', ...res };
  } catch (err) {
    cap2b = captureError(err);
  }
  trace({ scenario: 'S2b-wrong-type', target_slug: targetSlug, captured: cap2b });

  // Variant 2c — unknown field
  let cap2c: Record<string, unknown>;
  try {
    const res = await composio.tools.execute(targetSlug, {
      userId,
      arguments: { not_a_real_field: 'x' },
      version: '00000000_00',
    });
    cap2c = { kind: 'result', ...res };
  } catch (err) {
    cap2c = captureError(err);
  }
  trace({ scenario: 'S2c-unknown-field', target_slug: targetSlug, captured: cap2c });

  // The point of L5 is to capture reality. If Composio happily forwards
  // garbage to GitHub and GitHub responds with 404, that's an expectation gap
  // we want recorded — NOT a reason to massage the assertion. The minimum
  // contract is: at least one variant must come back as some kind of failure
  // (SDK threw or `successful: false`). All three results are dumped to the
  // trace either way for evidence.md.
  const isFailure = (cap: Record<string, unknown>) =>
    cap.kind === 'error' ||
    (cap.kind === 'result' && (cap as { successful?: boolean }).successful === false);
  expect(
    [cap2a, cap2b, cap2c].some(isFailure),
    `expected at least one schema-violation to fail. captured: ${JSON.stringify({
      a: cap2a,
      b: cap2b,
      c: cap2c,
    }).slice(0, 800)}`,
  ).toBe(true);
}, 90_000);

// ---------------------------------------------------------------------------
// Scenario 3 — invalid Composio API key
// ---------------------------------------------------------------------------
test('S3 live: invalid Composio API key -> auth failure', async () => {
  // Bogus / random literal — safe to commit (not a real key).
  const bogus = createComposioClient({ apiKey: 'ak_invalid_key_for_testing_l5_failure' });
  let captured: Record<string, unknown>;
  try {
    // Use tools.get with a real toolkit name — the request travels and is
    // auth-checked at the API gateway.
    const tools = await bogus.tools.get('aischool-l5-bogus', {
      tools: ['HACKERNEWS_GET_FRONTPAGE'],
    });
    captured = { kind: 'result', tools_kind: typeof tools, tools_len: Array.isArray(tools) ? tools.length : -1 };
  } catch (err) {
    captured = captureError(err);
  }
  trace({ scenario: 'S3-invalid-api-key', captured });

  expect(captured).toBeDefined();
  // Expect 401/403 OR a clear "API key" / "unauthorized" message from the SDK.
  const status = (captured as { status?: number }).status ?? 0;
  const message = String((captured as { message?: string }).message ?? '');
  const isAuthFailure =
    captured.kind === 'error' &&
    (status === 401 ||
      status === 403 ||
      /(api[\s-_]?key|unauthor|forbidden|invalid.*key|authentic)/i.test(message));
  expect(
    isAuthFailure,
    `expected auth failure with status 401/403 or auth-shaped message, got: ${JSON.stringify(captured).slice(0, 600)}`,
  ).toBe(true);
}, 60_000);

// ---------------------------------------------------------------------------
// Scenario 4 — non-existent tool slug
// ---------------------------------------------------------------------------
test('S4 live: non-existent tool slug -> failure', async () => {
  const composio = createComposioClient();
  let captured: Record<string, unknown>;
  try {
    const res = await composio.tools.execute('GITHUB_DOES_NOT_EXIST_FAKE_TOOL_SLUG', {
      userId: L2_USER_ID,
      arguments: {},
      version: '00000000_00',
    });
    captured = { kind: 'result', ...res };
  } catch (err) {
    captured = captureError(err);
  }
  trace({ scenario: 'S4-unknown-tool', captured });

  const isFailure =
    (captured.kind === 'error' &&
      /(not.*found|unknown|invalid|does not exist|no.*tool)/i.test(
        String((captured as { message?: string }).message ?? ''),
      )) ||
    (captured.kind === 'result' && (captured as { successful?: boolean }).successful === false);
  expect(
    isFailure,
    `expected failure for fake slug, got: ${JSON.stringify(captured).slice(0, 600)}`,
  ).toBe(true);
}, 60_000);

