### source/lib/session-helpers.ts
```ts
/**
 * session-helpers.ts
 *
 * Local helper utilities for parsing pi session JSONL files.
 * Adapted from L1's jsonl-helpers.ts; updated with session structure
 * knowledge confirmed in L1 + L2 live investigation.
 *
 * Session JSONL structure (confirmed empirically):
 *   ~/.pi/agent/sessions/<cwd-slug>/<timestamp>_<uuid>.jsonl
 *
 * Each JSONL line is a JSON object with a 'type' field:
 *   - "session"              — first line; metadata (version, id, cwd)
 *   - "model_change"         — { provider, modelId } — the selected model
 *   - "thinking_level_change"— records thinking level
 *   - "message"              — user or assistant message
 *
 * Model is stored in TWO places:
 *   1. model_change entry: { type: "model_change", provider, modelId }
 *   2. assistant message entries: { message: { model: "<id>", provider: "..." } }
 *
 * The authoritative model identity for a session is model_change.modelId.
 */

import { existsSync, readdirSync, statSync } from "node:fs";
import { join } from "node:path";
import { homedir } from "node:os";

export interface SessionEntry {
  type: string;
  id?: string;
  parentId?: string;
  timestamp?: string | number;
  provider?: string;
  modelId?: string;
  message?: {
    role: string;
    content: Array<{ type: string; text: string }>;
    model?: string;
    provider?: string;
    [key: string]: unknown;
  };
  [key: string]: unknown;
}

/**
 * Convert a filesystem path to the slug pi uses for session subdirectory names.
 *
 * Algorithm (discovered empirically in L1 live investigation):
 *   slug = '-' + (path + '/').replace(/\//g, '-') + '-'
 *
 * Example: /private/tmp/pi-l2-flag-XXXXX
 *   -> with trailing slash: /private/tmp/pi-l2-flag-XXXXX/
 *   -> replace /: -private-tmp-pi-l2-flag-XXXXX-
 *   -> wrap with dashes: --private-tmp-pi-l2-flag-XXXXX--
 */
export function pathToSessionSlug(dir: string): string {
  const withTrailing = dir.endsWith("/") ? dir : dir + "/";
  return "-" + withTrailing.replace(/\//g, "-") + "-";
}

/**
 * Resolve the real filesystem path for a cwd.
 * On macOS, /tmp -> /private/tmp and /var -> /private/var (symlinks).
 * Pi calls realpath() before computing the session slug.
 */
export function realCwd(cwd: string): string {
  if (cwd.startsWith("/tmp") && existsSync("/private/tmp")) {
    return "/private" + cwd;
  }
  if (cwd.startsWith("/var") && existsSync("/private/var")) {
    return "/private" + cwd;
  }
  return cwd;
}

/**
 * Resolve the session directory pi uses for a given working directory.
 */
export function resolveSessionDir(
  cwd: string,
  sessionRoot: string = join(homedir(), ".pi", "agent", "sessions")
): string {
  const resolved = realCwd(cwd);
  const slug = pathToSessionSlug(resolved);
  return join(sessionRoot, slug);
}

/**
 * Return the filename of the newest .jsonl file in a directory, or null if none.
 */
export function newestJsonlFile(dir: string): string | null {
  if (!existsSync(dir)) return null;
  const entries = readdirSync(dir).filter((f) => f.endsWith(".jsonl"));
  if (entries.length === 0) return null;
  return entries
    .map((f) => ({ f, t: statSync(join(dir, f)).mtimeMs }))
    .sort((a, b) => b.t - a.t)[0].f;
}

/**
 * Extract the model ID from session JSONL entries.
 *
 * Priority:
 *   1. model_change entry's modelId field (most authoritative)
 *   2. assistant message's message.model field (fallback)
 */
export function extractModelId(entries: SessionEntry[]): string | undefined {
  // First: look for model_change entry
  for (const e of entries) {
    if (e.type === "model_change" && typeof e.modelId === "string") {
      return e.modelId;
    }
  }
  // Fallback: assistant message model field
  for (const e of entries) {
    if (e.type === "message" && e.message?.role === "assistant" && typeof e.message.model === "string") {
      return e.message.model;
    }
  }
  return undefined;
}

