import type { SandboxProvider } from "smithers-orchestrator/sandbox";

export type RemoteProviderKind = "docker" | "cloudflare" | "vercel" | "hetzner";

export type RemoteProviderConfig = {
  kind: RemoteProviderKind;
  image?: string;
  env?: Record<string, string>;
  region?: string;
  timeoutMs?: number;
};

export type RemoteRunEvidence = {
  provider: RemoteProviderKind;
  remoteRunId: string;
  workspaceId?: string;
  resourceIds: string[];
  logs: string[];
  cleanup: "not-started" | "complete" | "failed";
};

export function requiredEnv(kind: RemoteProviderKind): string[] {
  switch (kind) {
    case "docker": return [];
    case "cloudflare": return ["CLOUDFLARE_API_TOKEN"];
    case "vercel": return ["VERCEL_TOKEN"];
    case "hetzner": return ["HCLOUD_TOKEN", "HETZNER_SSH_KEY_NAME"];
  }
}

export function assertRemoteAccess(kind: RemoteProviderKind, env = process.env): void {
  const missing = requiredEnv(kind).filter((name) => !env[name]);
  if (missing.length) {
    throw new Error(`LIVE_ACCESS_BLOCKED:${kind}:${missing.join(",")}`);
  }
}

/**
 * Factory placeholder for live SandboxProvider adapters.
 *
 * This file is intentionally a contract, not fake success. Implementations must:
 * - create one isolated provider resource;
 * - execute the Smithers request bundle remotely;
 * - read the real result JSON;
 * - return provider run/resource IDs;
 * - cleanup and record evidence.
 */
export function createRemoteSandboxProvider(config: RemoteProviderConfig): SandboxProvider {
  assertRemoteAccess(config.kind);
  return {
    id: `${config.kind}-remote`,
    async run() {
      throw new Error(
        `REMOTE_PROVIDER_NOT_IMPLEMENTED:${config.kind}: implement against the live provider API before claiming evidence`,
      );
    },
  } satisfies SandboxProvider;
}

