import { createClient, type SupabaseClient } from '@supabase/supabase-js';

function required(name: string): string {
  const v = process.env[name];
  if (!v) {
    throw new Error(
      `Missing required env var: ${name}. Populate supabase/.env.local before running live tests.`,
    );
  }
  return v;
}

/** Creates a client using the anon key (subject to RLS). */
export function createAnonClient(): SupabaseClient {
  return createClient(required('SUPABASE_URL'), required('SUPABASE_ANON_KEY'), {
    auth: { persistSession: false, autoRefreshToken: false },
  });
}

/** Creates a client using the service_role key (BYPASSES RLS - server-only). */
export function createServiceRoleClient(): SupabaseClient {
  return createClient(required('SUPABASE_URL'), required('SUPABASE_SERVICE_ROLE_KEY'), {
    auth: { persistSession: false, autoRefreshToken: false },
  });
}

/** Creates a client that uses a specific JWT (e.g., a signed-in user's access_token). */
export function createUserClient(accessToken: string): SupabaseClient {
  return createClient(required('SUPABASE_URL'), required('SUPABASE_ANON_KEY'), {
    auth: { persistSession: false, autoRefreshToken: false },
    global: { headers: { Authorization: `Bearer ${accessToken}` } },
  });
