create policy "l7_upsert_insert_own" on public.agent_university_test_l7_upsert
  for insert with check (owner_id = (select auth.uid()));

-- UPDATE policy DENIES everything (false WITH CHECK)
create policy "l7_upsert_update_deny" on public.agent_university_test_l7_upsert
  for update using (owner_id = (select auth.uid()))
  with check (false);

------------------------------------------------------------
-- BT-L7-03 (ON DELETE CASCADE on RLS-protected tables)
------------------------------------------------------------
create table if not exists public.agent_university_test_l7_orders (
  id uuid primary key default gen_random_uuid(),
