);

alter table public.agent_university_test_l7_orders enable row level security;
alter table public.agent_university_test_l7_items enable row level security;

create policy "l7_orders_select_own" on public.agent_university_test_l7_orders
  for select using (owner_id = (select auth.uid()));

create policy "l7_orders_delete_own" on public.agent_university_test_l7_orders
  for delete using (owner_id = (select auth.uid()));

create policy "l7_items_select_own" on public.agent_university_test_l7_items
  for select using (owner_id = (select auth.uid()));

create policy "l7_items_delete_own" on public.agent_university_test_l7_items
  for delete using (owner_id = (select auth.uid()));

------------------------------------------------------------
-- BT-L7-04 (auth.users trigger + cascade)
------------------------------------------------------------
create table if not exists public.agent_university_test_l7_profiles (
  user_id uuid primary key references auth.users(id) on delete cascade,
  display_name text not null default 'pending',
  created_at timestamptz not null default now()
);

alter table public.agent_university_test_l7_profiles enable row level security;

create policy "l7_profiles_select_own" on public.agent_university_test_l7_profiles
  for select using (user_id = (select auth.uid()));

create or replace function public.au_test_l7_handle_new_user() returns trigger language plpgsql security definer as $$
begin
  -- Only create profile rows for test users (email pattern match)
  -- Important: bypass RLS via security definer; FK ensures cleanup on user delete
  if new.email is not null and new.email like 'au-l7-%@example.com' then
    insert into public.agent_university_test_l7_profiles (user_id, display_name)
    values (new.id, coalesce(new.email, 'auth-user'));
  end if;
  return new;
end;
$$;

drop trigger if exists au_test_l7_on_auth_user_created on auth.users;
create trigger au_test_l7_on_auth_user_created
  after insert on auth.users
  for each row execute function public.au_test_l7_handle_new_user();

