);

alter table public.agent_university_test_l7_docs enable row level security;

create policy "l7_docs_select_own" on public.agent_university_test_l7_docs
  for select using (owner_id = (select auth.uid()));

------------------------------------------------------------
-- BT-L7-06 (Array column .overlaps)
------------------------------------------------------------
create table if not exists public.agent_university_test_l7_tagged (
