alter table public.agent_university_test_l7_tagged enable row level security;

create policy "l7_tagged_select_own" on public.agent_university_test_l7_tagged
  for select using (owner_id = (select auth.uid()));

------------------------------------------------------------
-- BT-L7-07 (Two-level embedded SELECT with independent RLS)
------------------------------------------------------------
create table if not exists public.agent_university_test_l7_teams (
  id uuid primary key default gen_random_uuid(),
  name text
);

create table if not exists public.agent_university_test_l7_team_members (
  team_id uuid not null references public.agent_university_test_l7_teams(id) on delete cascade,
  user_id uuid not null references auth.users(id) on delete cascade,
