);

alter table public.agent_university_test_l7_teams enable row level security;
alter table public.agent_university_test_l7_team_members enable row level security;
alter table public.agent_university_test_l7_team_items enable row level security;

-- Helper function to avoid recursive policy evaluation (Gap #14 lesson)
create or replace function public.au_test_l7_user_team_ids() returns setof uuid language sql stable security definer as $$
  select team_id from public.agent_university_test_l7_team_members where user_id = auth.uid();
$$;

create policy "l7_teams_select_if_member" on public.agent_university_test_l7_teams
  for select using (id in (select au_test_l7_user_team_ids()));

create policy "l7_team_members_select_if_team_member" on public.agent_university_test_l7_team_members
  for select using (team_id in (select au_test_l7_user_team_ids()));

create policy "l7_team_items_select_own" on public.agent_university_test_l7_team_items
  for select using (owner_id = (select auth.uid()));

------------------------------------------------------------
-- BT-L7-08 (count modes — reuse l7_tagged table with many rows; no new schema needed)
