-- BT-L7-09 (SECURITY DEFINER vs INVOKER)
------------------------------------------------------------
create or replace function public.au_test_l7_fn_definer(target_uid uuid) returns integer language sql security definer as $$
  select count(*)::int from public.agent_university_test_l7_docs where owner_id = target_uid;
$$;

create or replace function public.au_test_l7_fn_invoker(target_uid uuid) returns integer language sql security invoker as $$
  select count(*)::int from public.agent_university_test_l7_docs where owner_id = target_uid;
$$;

-- Grant execute to authenticated for both
grant execute on function public.au_test_l7_fn_definer(uuid) to authenticated;
grant execute on function public.au_test_l7_fn_invoker(uuid) to authenticated;

