### source/tests/routing.live.test.ts
```ts
/**
 * routing.live.test.ts — L2: Provider Routing and Cancellation
 * Evidence class: Live behavioral test / Live failure-mode test
 * POC level: L2
 * Service boundary: https://ai-gateway.vercel.sh (via AI SDK createGateway + streamText)
 * Auth required: AI_GATEWAY_API_KEY
 *
 * Behavioral tests:
 *   BT-001: Explicit gateway client (createGateway with explicit apiKey) works even when
 *           AI_GATEWAY_API_KEY env var is set to a sentinel bad value — explicit apiKey wins.
 *   BT-002: Custom fetch interceptor captures outbound URL and Authorization header.
 *   BT-003: AbortController mid-stream cancellation terminates within 500ms; no further
 *           chunks arrive after abort; error is AbortError.
 *   BT-004: Tool calling — stream emits a tool-call part; executing the tool continues the
 *           response.
 *   BT-005: onFinish callback fires exactly once with text, usage, finishReason.
 *   BT-006: Invalid base URL fails with informative network error within 10s; doesn't hang.
 *
 * What "cheating" looks like:
 *   - Mocking createGateway or streamText to return canned responses.
 *   - Stubbing the custom fetch to return a fake response.
 *   - Setting AbortController.abort() before the stream starts.
 *   - Asserting only that a function was called.
 */

import { config } from 'dotenv';
import { resolve } from 'path';
import { describe, it, expect, beforeAll } from 'vitest';
import {
  createExplicitGateway,
  makeCapturingFetch,
  streamWithAbort,
  streamWithTool,
  streamWithOnFinish,
  streamWithInvalidBaseURL,
  type CapturedRequest,
  type AbortResult,
  type ToolResult,
  type OnFinishResult,
  type InvalidBaseURLResult,
} from '../src/routing.js';

// Load .env.local before any live calls
config({ path: resolve(import.meta.dirname, '../.env.local') });

beforeAll(() => {
  if (!process.env.AI_GATEWAY_API_KEY) {
    throw new Error(
      '[L2] AI_GATEWAY_API_KEY is not set. ' +
      'Copy source/.env.example to source/.env.local and add your key.'
    );
  }
});

// ---------------------------------------------------------------------------
// BT-001: Explicit gateway client — explicit apiKey wins over env sentinel
// Label: Live behavioral test
// ---------------------------------------------------------------------------
describe('BT-001: Explicit gateway client overrides env sentinel', () => {
  it('[Live behavioral test] explicit apiKey in createGateway wins when env has a bad sentinel value', async () => {
    const realKey = process.env.AI_GATEWAY_API_KEY!;

    // Set env to a sentinel bad value before the call
    process.env.AI_GATEWAY_API_KEY = 'sentinel_bad_value_should_not_be_used';

    let result: string | null = null;
    let errorCaught: Error | null = null;

    try {
      const gw = createExplicitGateway(realKey);
      result = await gw.generateText('Reply with the single word: pong');
    } catch (err) {
      errorCaught = err as Error;
    } finally {
      // Restore the real key
      process.env.AI_GATEWAY_API_KEY = realKey;
    }

    // The call must succeed with the explicit key — sentinel env value must not be used
    expect(errorCaught).toBeNull();
    expect(result).not.toBeNull();
    expect(result!.toLowerCase()).toContain('pong');

    console.log(JSON.stringify({
      op: 'BT-001 explicit gateway override',
      resultPreview: result?.substring(0, 60),
      sentinelEnvWasIgnored: true,
      verdict: 'PASS — explicit apiKey wins over env sentinel',
    }));
  });
});

// ---------------------------------------------------------------------------
// BT-002: Custom fetch interceptor captures outbound URL and Authorization header
// Label: Live behavioral test
// ---------------------------------------------------------------------------
describe('BT-002: Custom fetch interceptor captures outbound URL and auth header', () => {
  let captured: CapturedRequest[];

  beforeAll(async () => {
    const key = process.env.AI_GATEWAY_API_KEY!;
    const { captures, result } = await makeCapturingFetch(key);
    captured = captures;

    console.log(JSON.stringify({
      op: 'BT-002 fetch interceptor',
      captureCount: captures.length,
      urls: captures.map(c => c.url),
      authHeaderPresent: captures.some(c => !!c.authHeader),
      stainlessHeaders: captures.map(c => c.stainlessHeaders),
      resultPreview: result.substring(0, 60),
    }));
  });

  it('[Live behavioral test] at least one outbound fetch URL starts with https://ai-gateway.vercel.sh', () => {
    expect(captured.length).toBeGreaterThan(0);
    const gatewayCall = captured.find(c => c.url.startsWith('https://ai-gateway.vercel.sh'));
    expect(gatewayCall).toBeDefined();
    console.log(JSON.stringify({
      op: 'BT-002 URL check',
      capturedURL: gatewayCall?.url ?? 'none',
    }));
  });

  it('[Live behavioral test] Authorization header is Bearer <key> format', () => {
    const gatewayCall = captured.find(c => c.url.startsWith('https://ai-gateway.vercel.sh'));
    expect(gatewayCall).toBeDefined();
    expect(gatewayCall!.authHeader).toMatch(/^Bearer vck_/);
    // Log sanitized: only prefix visible
    const sanitized = gatewayCall!.authHeader.substring(0, 14) + '***';
    console.log(JSON.stringify({
      op: 'BT-002 auth header',
      authHeaderSanitized: sanitized,
      verdict: 'PASS — Bearer vck_ format confirmed',
    }));
  });

  it('[Live behavioral test] telemetry headers (x-stainless-* or user-agent) are present', () => {
    const gatewayCall = captured.find(c => c.url.startsWith('https://ai-gateway.vercel.sh'));
    expect(gatewayCall).toBeDefined();
    // The SDK injects x-stainless-* or similar telemetry headers
    const hasStainless = gatewayCall!.stainlessHeaders.length > 0 ||
      gatewayCall!.otherHeaderKeys.some(k => k.toLowerCase().includes('user-agent') || k.toLowerCase().includes('stainless'));
    expect(hasStainless).toBe(true);
    console.log(JSON.stringify({
      op: 'BT-002 telemetry headers',
      stainlessHeaders: gatewayCall!.stainlessHeaders,
      otherHeaderKeys: gatewayCall!.otherHeaderKeys,
    }));
  });
});

// ---------------------------------------------------------------------------
// BT-003: AbortController mid-stream cancellation
// Label: Live behavioral test
// ---------------------------------------------------------------------------
describe('BT-003: AbortController mid-stream cancellation', () => {
  let abortResult: AbortResult;

  beforeAll(async () => {
    abortResult = await streamWithAbort({
      model: 'openai/gpt-5.4-nano',
      chunksBeforeAbort: 2,
      abortTimeoutMs: 500,
    });

    console.log(JSON.stringify({
      op: 'BT-003 abort result',
      chunksBeforeAbort: abortResult.chunksCollectedBeforeAbort,
      terminatedWithin500ms: abortResult.terminatedWithinMs,
      errorName: abortResult.errorName,
      errorMessage: abortResult.errorMessage?.substring(0, 150),
      chunksAfterAbort: abortResult.chunksAfterAbort,
    }));
  });

  it('[Live behavioral test] stream terminates within 500ms of abort signal being sent', () => {
    expect(abortResult.terminatedWithinMs).toBeLessThanOrEqual(500);
  });

  it('[Live behavioral test] error is an AbortError, not a network error', () => {
    if (abortResult.errorName !== null) {
      // AbortError or contains "abort" in name or message
      const isAbortRelated = (
        abortResult.errorName.toLowerCase().includes('abort') ||
        (abortResult.errorMessage ?? '').toLowerCase().includes('abort')
      );
      expect(isAbortRelated).toBe(true);
    }
    // If no error was thrown but stream terminated cleanly, that's also valid
    // (some SDK versions may not throw on abort, they just terminate the stream)
    expect(abortResult.streamEnded).toBe(true);
  });

  it('[Live behavioral test] no further chunks arrive after abort', () => {
    expect(abortResult.chunksAfterAbort).toBe(0);
  });
});

// ---------------------------------------------------------------------------
// BT-004: Tool calling — stream emits tool-call part; tool executes; response continues
// Label: Live behavioral test
// ---------------------------------------------------------------------------
describe('BT-004: Tool calling with getWeather tool', () => {
  let toolResult: ToolResult;

  beforeAll(async () => {
    toolResult = await streamWithTool();

    console.log(JSON.stringify({
      op: 'BT-004 tool calling result',
      toolCallCount: toolResult.toolCallCount,
      toolNames: toolResult.toolNames,
      toolExecuted: toolResult.toolExecuted,
      finalText: toolResult.finalText?.substring(0, 150),
      finishReason: toolResult.finishReason,
    }));
  });

  it('[Live behavioral test] stream emits at least one tool-call part', () => {
    expect(toolResult.toolCallCount).toBeGreaterThanOrEqual(1);
  });

  it('[Live behavioral test] the emitted tool-call has the right tool name (getWeather)', () => {
    expect(toolResult.toolNames).toContain('getWeather');
  });

  it('[Live behavioral test] tool execute function was called', () => {
    expect(toolResult.toolExecuted).toBe(true);
  });

  it('[Live behavioral test] final response text is non-empty (response continued after tool)', () => {
    expect(toolResult.finalText).toBeTruthy();
    expect(toolResult.finalText!.length).toBeGreaterThan(0);
  });
});

// ---------------------------------------------------------------------------
// BT-005: onFinish callback fires exactly once
// Label: Live behavioral test
// ---------------------------------------------------------------------------
describe('BT-005: onFinish callback fires exactly once', () => {
  let onFinishResult: OnFinishResult;

  beforeAll(async () => {
    onFinishResult = await streamWithOnFinish();

    console.log(JSON.stringify({
      op: 'BT-005 onFinish result',
      callCount: onFinishResult.callCount,
      hasText: onFinishResult.hasText,
      finishReason: onFinishResult.finishReason,
      usagePresent: onFinishResult.usagePresent,
      inputTokens: onFinishResult.inputTokens,
      outputTokens: onFinishResult.outputTokens,
    }));
  });

  it('[Live behavioral test] onFinish fires exactly once', () => {
    expect(onFinishResult.callCount).toBe(1);
  });

  it('[Live behavioral test] onFinish receives non-empty text', () => {
    expect(onFinishResult.hasText).toBe(true);
  });

  it('[Live behavioral test] onFinish receives finishReason', () => {
    expect(['stop', 'length', 'tool-calls', 'content-filter', 'other']).toContain(
      onFinishResult.finishReason
    );
  });

  it('[Live behavioral test] onFinish receives usage with outputTokens > 0', () => {
    expect(onFinishResult.usagePresent).toBe(true);
    expect(onFinishResult.outputTokens).toBeGreaterThan(0);
  });
});

// ---------------------------------------------------------------------------
// BT-006: Invalid base URL fails with informative error within 10s; doesn't hang
// Label: Live failure-mode test
// ---------------------------------------------------------------------------
describe('BT-006: Invalid base URL fails with network error within 10s', () => {
  let invalidURLResult: InvalidBaseURLResult;

  beforeAll(async () => {
    invalidURLResult = await streamWithInvalidBaseURL();

    console.log(JSON.stringify({
      op: 'BT-006 invalid base URL result',
      threwError: invalidURLResult.threwError,
      errorName: invalidURLResult.errorName,
      errorMessage: invalidURLResult.errorMessage?.substring(0, 200),
      elapsedMs: invalidURLResult.elapsedMs,
    }));
  });

  it('[Live failure-mode test] call throws an error', () => {
    expect(invalidURLResult.threwError).toBe(true);
  });

  it('[Live failure-mode test] error is informative network error (not silent hang)', () => {
    expect(invalidURLResult.errorMessage).toBeTruthy();
    expect(invalidURLResult.errorMessage!.length).toBeGreaterThan(0);
  });

  it('[Live failure-mode test] fails within 10s — does not hang indefinitely', () => {
    expect(invalidURLResult.elapsedMs).toBeLessThanOrEqual(10_000);
  });
});

